<script setup lang="ts">
import {onMounted,ref} from 'vue';import {AlertTriangle,CheckCircle2,FileClock,FileText,RefreshCw,Sparkles} from 'lucide-vue-next';import KpiCard from '../components/common/KpiCard.vue';import StatusBadge from '../components/common/StatusBadge.vue';import {reportApi} from '../api/reports';const reports=ref<any[]>([]),selected=ref<any>(null),pipeline=ref<any[]>([]),updating=ref(false);async function load(){reports.value=await reportApi.list();selected.value=reports.value[0];if(selected.value)pipeline.value=await reportApi.pipeline(selected.value.id)}async function update(){updating.value=true;await reportApi.updateAll();setTimeout(()=>updating.value=false,900)}onMounted(load)
</script>
<template><div><div class="page-actions"><button class="btn" @click="update"><RefreshCw :size="16"/>{{updating?'更新中...':'更新全部财报'}}</button><button class="btn">只更新最新财报</button><button class="btn">重新解析</button><button class="btn primary"><Sparkles :size="16"/>生成基本面分析</button></div><div class="kpi-grid grid"><KpiCard label="已收录财报" value="1,286份" change="覆盖 128 家公司" tone="blue" :icon="FileText"/><KpiCard label="待解析" value="18份" change="队列正常" tone="orange" :icon="FileClock"/><KpiCard label="解析成功率" value="96.8%" change="较上周 +1.2pp" tone="green" :icon="CheckCircle2"/><KpiCard label="本周新增公告" value="84份" change="较上周 +16" tone="purple" :icon="FileText"/><KpiCard label="待复核异常" value="6份" change="需人工确认" tone="red" :icon="AlertTriangle"/></div><div class="split-3"><aside class="panel"><div class="panel-title"><h2>财报筛选</h2></div><div class="list-panel"><div class="list-item active"><span>全部财报</span><span>1,286</span></div><div class="list-item"><span>年度报告</span><span>412</span></div><div class="list-item"><span>第一季度报告</span><span>318</span></div><div class="list-item"><span>半年度报告</span><span>286</span></div><div class="list-item"><span>第三季度报告</span><span>270</span></div><div class="list-item"><span>公司公告</span><span>642</span></div></div></aside><section class="panel"><div class="panel-title"><h2>财报列表</h2><span class="spacer muted">{{reports.length}} 条演示数据</span></div><div class="table-wrap"><table><thead><tr><th>公司 / 财报</th><th>报告期</th><th>发布日期</th><th>解析进度</th><th>完整度</th><th>状态</th></tr></thead><tbody><tr v-for="x in reports" :key="x.id" @click="selected=x"><td><b>{{x.title}}</b><br/><small class="muted">{{x.ts_code}}</small></td><td>{{x.report_period}}</td><td>{{x.publish_date}}</td><td><div class="progress"><i :style="{width:x.parse_progress+'%'}"></i></div></td><td>{{x.extraction_completeness}}%</td><td><StatusBadge :text="x.parse_status==='success'?'解析成功':'待解析'" :tone="x.parse_status==='success'?'success':'warning'"/></td></tr></tbody></table></div></section><aside class="panel" v-if="selected"><div class="panel-title"><h2>财报详情</h2></div><div class="panel-body"><h3>{{selected.title}}</h3><p class="muted">{{selected.ts_code}} · {{selected.report_period}}</p><p>{{selected.summary}}</p><hr/><h3>抽取质量</h3><p>表格完整度：{{selected.extraction_completeness}}%</p><div class="progress"><i :style="{width:selected.extraction_completeness+'%'}"></i></div><h3>来源</h3><p>{{selected.source}}</p><p class="muted">{{selected.source_url}}</p></div><p class="disclaimer">当前为 mock 报告，不代表真实公开信息。</p></aside></div><article class="panel" style="margin-top:14px"><div class="panel-title"><h2>处理流程</h2></div><div class="panel-body" style="display:flex;justify-content:space-around"><div v-for="(x,i) in pipeline" :key="x.name" style="text-align:center"><span class="kpi-icon green" style="margin:auto"><CheckCircle2 :size="18"/></span><b style="display:block;margin-top:8px">{{x.name}}</b><small class="muted">步骤 {{i+1}}</small></div></div></article></div></template>

